vtest(
  'put then get returns the stored value and meta',
  'Both `value` and `meta` survive serialization into IndexedDB and back.',
  async () => {
    const users = await Effect.runPromise(
      IDBCacheEntity.make<User>({
        dbName: nextDb(),
        name: 'User',
        idField: 'id',
      }),
    );
